const express = require('express');
const morgan = require('morgan');
const fs = require('fs');
const path = require('path');
const app = express();

const logDirectory = path.join(__dirname, 'logs');
fs.existsSync(logDirectory) || fs.mkdirSync(logDirectory);

const accessLogStream = fs.createWriteStream(path.join(logDirectory, 'access.log'), { flags: 'a' });

app.use(express.json());
app.use(express.urlencoded({ extended: true }));

app.use(morgan(':remote-addr - :remote-user ":method :url HTTP/:http-version" :status :res[content-length] - :response-time ms - User: :req[username] - Custom Header: :req[custom-header]', {
  stream: accessLogStream,
  skip: (req, res) => res.statusCode < 400
}));

app.post('/log', (req, res) => {
  const { username, customHeader } = req.body;
  const ip = req.ip;

  const sanitizedUsername = username.replace(/[^a-zA-Z0-9_]/g, '');
  const sanitizedCustomHeader = customHeader.replace(/[^a-zA-Z0-9_]/g, '');

  const logMessage = `User: ${sanitizedUsername}, IP: ${ip}, Custom Header: ${sanitizedCustomHeader}`;
  fs.appendFileSync(path.join(logDirectory, 'audit.log'), logMessage + '\n');

  res.send('Log entry created');
});

app.listen(3000, () => {
  console.log('Server is running on port 3000');
});